import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Define a maximum buffer size
        int maxSize = 10;

        // Ensure that user input does not exceed the buffer size
        if (name.length() > maxSize) {
            System.out.println("Input exceeds maximum buffer size. Please enter a shorter name.");
            return;
        }

        char[] buffer = new char[maxSize]; // Buffer of fixed size

        // Copy the user input into the buffer with bounds checking
        for (int i = 0; i < name.length() && i < maxSize; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Hello, " + new String(buffer).trim()); // Trim any extra characters beyond the actual input
    }
}
